import { createClient } from '@sanity/client';

const projectId = import.meta.env.SANITY_PROJECT_ID || 'placeholder';
const dataset = import.meta.env.SANITY_DATASET || 'production';

export const client = createClient({
  projectId,
  dataset,
  apiVersion: '2026-03-31',
  useCdn: true,
});

export { projectId, dataset };

// ---------------------------------------------------------------------------
// Shared types — lightweight interfaces matching schema shapes.
// Full Sanity-generated types can replace these later.
// ---------------------------------------------------------------------------

export interface SanitySlug {
  _type: 'slug';
  current: string;
}

export interface PortableTextBlock {
  _type: string;
  _key: string;
  [key: string]: unknown;
}

export interface SanityImage {
  _type: 'image';
  asset: { _ref: string; _type: 'reference' };
}

export interface Page {
  _id: string;
  _type: 'page';
  title: string;
  slug: SanitySlug;
  body: PortableTextBlock[];
  language: 'en' | 'zh';
}

export interface Sermon {
  _id: string;
  _type: 'sermon';
  title: string;
  speaker?: string;
  date?: string;
  series?: string;
  scripture?: string;
  videoId?: string;
  language: 'en' | 'zh';
}

export interface Event {
  _id: string;
  _type: 'event';
  title: string;
  date?: string;
  endDate?: string;
  time?: string;
  location?: string;
  description?: PortableTextBlock[];
  recurring?: boolean;
  language: 'en' | 'zh';
}

export interface Ministry {
  _id: string;
  _type: 'ministry';
  name: string;
  description?: PortableTextBlock[];
  leader?: { _ref: string };
  meetingTime?: string;
  language: 'en' | 'zh';
}

export interface SocialLink {
  platform: string;
  url: string;
}

export interface SiteSettings {
  _id: string;
  _type: 'siteSettings';
  churchName: string;
  address?: string;
  phone?: string;
  email?: string;
  socialLinks?: SocialLink[];
  language: 'en' | 'zh';
}

export interface NavChild {
  label: string;
  href?: string;
}

export interface NavItem {
  label: string;
  href?: string;
  children?: NavChild[];
}

export interface Navigation {
  _id: string;
  _type: 'navigation';
  navItems: NavItem[];
  language: 'en' | 'zh';
}

export interface ServiceTime {
  label: string;
  time: string;
}

export interface Pillar {
  title: string;
  description?: string;
}

export interface NextStep {
  title: string;
  body?: string;
  href?: string;
  image?: SanityImage;
}

export interface MosaicImage extends SanityImage {
  alt?: string;
}

export interface HomePage {
  _id: string;
  _type: 'homePage';
  heroImage?: SanityImage;
  heroTitle: string;
  heroSubtitle?: string;
  heroCtaText?: string;
  heroCtaHref?: string;
  serviceTimes?: ServiceTime[];
  mosaicImages?: MosaicImage[];
  pillars?: Pillar[];
  nextSteps?: NextStep[];
  language: 'en' | 'zh';
}

// ---------------------------------------------------------------------------
// GROQ query helpers
// ---------------------------------------------------------------------------

type Language = 'en' | 'zh';

/**
 * Fetch a page by its slug and language.
 */
export async function getPageBySlug(
  slug: string,
  language: Language = 'en',
): Promise<Page | null> {
  return client.fetch<Page | null>(
    `*[_type == "page" && slug.current == $slug && language == $language][0]`,
    { slug, language },
  );
}

/**
 * Fetch all sermons for a language, newest first.
 */
export async function getSermons(language: Language = 'en'): Promise<Sermon[]> {
  return client.fetch<Sermon[]>(
    `*[_type == "sermon" && language == $language] | order(date desc)`,
    { language },
  );
}

/**
 * Fetch upcoming events for a language, soonest first.
 */
export async function getEvents(language: Language = 'en'): Promise<Event[]> {
  return client.fetch<Event[]>(
    `*[_type == "event" && language == $language] | order(date asc)`,
    { language },
  );
}

/**
 * Fetch all ministries for a language.
 */
export async function getMinistries(
  language: Language = 'en',
): Promise<Ministry[]> {
  return client.fetch<Ministry[]>(
    `*[_type == "ministry" && language == $language] | order(name asc)`,
    { language },
  );
}

/**
 * Fetch the singleton site-settings document for a language.
 * Singleton IDs follow the pattern `{type}-{lang}` per D-decision.
 */
export async function getSiteSettings(
  language: Language = 'en',
): Promise<SiteSettings | null> {
  return client.fetch<SiteSettings | null>(
    `*[_type == "siteSettings" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch the singleton navigation document for a language.
 */
export async function getNavigation(
  language: Language = 'en',
): Promise<Navigation | null> {
  return client.fetch<Navigation | null>(
    `*[_type == "navigation" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch the singleton home-page document for a language.
 */
export async function getHomePage(
  language: Language = 'en',
): Promise<HomePage | null> {
  return client.fetch<HomePage | null>(
    `*[_type == "homePage" && language == $language][0]`,
    { language },
  );
}

// ---------------------------------------------------------------------------
// Image helpers
// ---------------------------------------------------------------------------

/**
 * Resolve a Sanity image asset reference to a CDN URL.
 *
 * Asset refs look like `image-<id>-<WxH>-<ext>`. We strip the `image-`
 * prefix and replace the last `-` (before the extension) with `.` to get
 * the filename portion used in the CDN path.
 *
 * Example ref: `image-abc123-800x600-jpg`
 * Result:      `https://cdn.sanity.io/images/{projectId}/{dataset}/abc123-800x600.jpg`
 */
export function urlForImage(
  image: SanityImage | undefined | null,
  options?: { width?: number; format?: string },
): string {
  if (!image?.asset?._ref) return '';

  const ref = image.asset._ref;
  // Strip leading "image-" and split on the last "-" to get id and extension
  const withoutPrefix = ref.replace(/^image-/, '');
  const lastDash = withoutPrefix.lastIndexOf('-');
  if (lastDash === -1) return '';

  const idAndDimensions = withoutPrefix.slice(0, lastDash);
  const ext = withoutPrefix.slice(lastDash + 1);
  const filename = `${idAndDimensions}.${ext}`;

  let url = `https://cdn.sanity.io/images/${projectId}/${dataset}/${filename}`;

  const params = new URLSearchParams();
  if (options?.width) params.set('w', String(options.width));
  if (options?.format) params.set('fm', options.format);
  const qs = params.toString();
  if (qs) url += `?${qs}`;

  return url;
}

// ---------------------------------------------------------------------------
// Visual Editing — draft-aware query helper for server-rendered preview
// ---------------------------------------------------------------------------

const isVisualEditingEnabled =
  import.meta.env.PUBLIC_SANITY_VISUAL_EDITING_ENABLED === 'true';

/**
 * Draft-aware query helper for preview/visual-editing contexts.
 *
 * When `PUBLIC_SANITY_VISUAL_EDITING_ENABLED` is `'true'`:
 *   - Uses `perspective: 'previewDrafts'` so editors see unpublished changes
 *   - Injects `SANITY_API_READ_TOKEN` (server-only) for authenticated draft access
 *   - Enables stega encoding and result source maps for click-to-edit overlays
 *
 * When disabled, falls back to published perspective with no token or stega.
 *
 * This is a *parallel* helper — existing getPageBySlug / getSermons / etc.
 * remain unchanged for static build-time fetching.
 */
export async function loadQuery<T = unknown>(
  query: string,
  params: Record<string, unknown> = {},
): Promise<{ data: T }> {
  if (isVisualEditingEnabled) {
    const token = import.meta.env.SANITY_API_READ_TOKEN;
    if (!token) {
      throw new Error(
        '[sanity/loadQuery] PUBLIC_SANITY_VISUAL_EDITING_ENABLED is true but ' +
          'SANITY_API_READ_TOKEN is not set. Add the token to your environment ' +
          '(server-only, no PUBLIC_ prefix).',
      );
    }

    if (import.meta.env.DEV) {
      console.debug('[sanity/loadQuery] perspective: previewDrafts (visual editing enabled)');
    }

    const data = await client.fetch<T>(query, params, {
      perspective: 'previewDrafts',
      stega: true,
      token,
      resultSourceMap: true,
    });
    return { data };
  }

  const data = await client.fetch<T>(query, params, {
    perspective: 'published',
  });
  return { data };
}

import { defineType, defineField } from 'sanity';

export const person = defineType({
  name: 'person',
  title: 'Person',
  type: 'document',
  fields: [
    defineField({
      name: 'name',
      title: 'Name',
      type: 'string',
      validation: (rule) => rule.required(),
    }),
    defineField({
      name: 'role',
      title: 'Role',
      type: 'string',
    }),
    defineField({
      name: 'bio',
      title: 'Bio',
      type: 'array',
      of: [{ type: 'block' }],
    }),
    defineField({
      name: 'photo',
      title: 'Photo',
      type: 'image',
      options: { hotspot: true },
    }),
    defineField({
      name: 'language',
      title: 'Language',
      type: 'string',
      options: { list: ['en', 'zh'] },
      initialValue: 'en',
      validation: (rule) => rule.required(),
    }),
  ],
  preview: {
    select: { title: 'name', subtitle: 'role', media: 'photo', language: 'language' },
    prepare: ({ title, subtitle, media, language }) => ({
      title: title || 'Unnamed',
      subtitle: [subtitle, language?.toUpperCase()].filter(Boolean).join(' · '),
      media,
    }),
  },
});

import { defineType, defineField } from 'sanity';

export const page = defineType({
  name: 'page',
  title: 'Page',
  type: 'document',
  fields: [
    defineField({
      name: 'title',
      title: 'Title',
      type: 'string',
      validation: (rule) => rule.required(),
    }),
    defineField({
      name: 'slug',
      title: 'Slug',
      type: 'slug',
      options: { source: 'title', maxLength: 96 },
      validation: (rule) => rule.required(),
    }),
    defineField({
      name: 'body',
      title: 'Body',
      type: 'array',
      of: [
        { type: 'block' },
        { type: 'heroBlock' },
        { type: 'imageMosaicBlock' },
        { type: 'accordionBlock' },
        { type: 'cardGridBlock' },
        { type: 'youtubeEmbedBlock' },
      ],
    }),
    defineField({
      name: 'language',
      title: 'Language',
      type: 'string',
      options: { list: ['en', 'zh'] },
      initialValue: 'en',
      validation: (rule) => rule.required(),
    }),
  ],
  preview: {
    select: { title: 'title', language: 'language' },
    prepare: ({ title, language }) => ({
      title: title || 'Untitled Page',
      subtitle: language?.toUpperCase(),
    }),
  },
});

---
interface AccordionItem {
  title: string;
  content: string;
}

interface Props {
  items: AccordionItem[];
}

const { items } = Astro.props;
---

<div class="accordion">
  {items.map((item) => (
    <details class="accordion__item">
      <summary class="accordion__summary">
        <span class="accordion__title">{item.title}</span>
        <svg class="accordion__chevron" width="20" height="20" viewBox="0 0 20 20" fill="none" aria-hidden="true">
          <path d="M6 8l4 4 4-4" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
        </svg>
      </summary>
      <div class="accordion__content">
        <p>{item.content}</p>
      </div>
    </details>
  ))}
</div>

<style>
  .accordion {
    display: flex;
    flex-direction: column;
  }

  .accordion__item {
    border-bottom: 1px solid var(--color-stone);
  }

  .accordion__summary {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--space-4);
    padding: var(--space-4) var(--space-2);
    cursor: pointer;
    list-style: none;
    transition: color var(--transition);
  }

  .accordion__summary::-webkit-details-marker {
    display: none;
  }

  .accordion__summary::marker {
    display: none;
    content: '';
  }

  .accordion__summary:hover {
    color: var(--color-terracotta);
  }

  .accordion__summary:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
    border-radius: var(--radius-sm);
  }

  .accordion__title {
    font-family: var(--font-body);
    font-size: var(--text-lg);
    font-weight: 600;
    color: var(--color-ink);
  }

  .accordion__chevron {
    flex-shrink: 0;
    color: var(--color-body);
    transition: transform var(--transition);
  }

  details[open] > .accordion__summary .accordion__chevron {
    transform: rotate(180deg);
  }

  .accordion__content {
    padding: 0 var(--space-2) var(--space-4);
  }

  .accordion__content p {
    font-family: var(--font-body);
    font-size: var(--text-base);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
    max-width: 48rem;
  }
</style>

import { defineType, defineField } from 'sanity';

export const accordionBlock = defineType({
  name: 'accordionBlock',
  title: 'Accordion Block',
  type: 'object',
  fields: [
    defineField({
      name: 'items',
      title: 'Items',
      type: 'array',
      of: [
        {
          type: 'object',
          name: 'accordionItem',
          title: 'Accordion Item',
          fields: [
            defineField({
              name: 'title',
              title: 'Title',
              type: 'string',
              validation: (rule) => rule.required(),
            }),
            defineField({
              name: 'content',
              title: 'Content',
              type: 'array',
              of: [{ type: 'block' }],
            }),
          ],
          preview: {
            select: { title: 'title' },
          },
        },
      ],
    }),
  ],
  preview: {
    select: { items: 'items' },
    prepare: ({ items }) => ({
      title: `Accordion (${items?.length ?? 0} items)`,
    }),
  },
});

---
interface Props {
  title: string;
  subtitle?: string;
  ctaText?: string;
  ctaHref?: string;
  backgroundImage: string;
}

const { title, subtitle, ctaText, ctaHref, backgroundImage } = Astro.props;
---

<section
  class="hero"
  style={`background-image: url('${backgroundImage}');`}
>
  <div class="hero__overlay">
    <div class="hero__content">
      <h1 class="hero__title">{title}</h1>
      {subtitle && <p class="hero__subtitle">{subtitle}</p>}
      {ctaText && ctaHref && (
        <a class="hero__cta" href={ctaHref}>{ctaText}</a>
      )}
    </div>
  </div>
</section>

<style>
  .hero {
    width: 100%;
    min-height: 28rem;
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .hero__overlay {
    position: absolute;
    inset: 0;
    background: linear-gradient(
      to bottom,
      rgba(26, 26, 46, 0.55) 0%,
      rgba(26, 26, 46, 0.72) 100%
    );
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .hero__content {
    position: relative;
    text-align: center;
    max-width: var(--max-width);
    padding: var(--space-12) var(--space-6);
    color: var(--color-bg);
  }

  .hero__title {
    font-family: var(--font-heading);
    font-size: var(--text-4xl);
    line-height: var(--leading-tight);
    color: var(--color-bg);
    margin-block-end: var(--space-4);
  }

  .hero__subtitle {
    font-family: var(--font-body);
    font-size: var(--text-lg);
    line-height: var(--leading-relaxed);
    color: var(--color-stone);
    max-width: 36rem;
    margin-inline: auto;
    margin-block-end: var(--space-8);
  }

  .hero__cta {
    display: inline-block;
    font-family: var(--font-body);
    font-size: var(--text-base);
    font-weight: 600;
    color: var(--color-bg);
    background-color: var(--color-terracotta);
    padding: var(--space-3) var(--space-8);
    border-radius: var(--radius-md);
    text-decoration: none;
    transition: background-color var(--transition), transform var(--transition);
  }

  .hero__cta:hover {
    background-color: #b3654b;
    transform: translateY(-1px);
  }

  .hero__cta:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  @media (max-width: 768px) {
    .hero {
      min-height: 22rem;
    }

    .hero__title {
      font-size: var(--text-2xl);
    }

    .hero__subtitle {
      font-size: var(--text-base);
    }

    .hero__content {
      padding: var(--space-8) var(--space-4);
    }
  }
</style>

// Object / block types
export { heroBlock } from './objects/heroBlock';
export { imageMosaicBlock } from './objects/imageMosaicBlock';
export { accordionBlock } from './objects/accordionBlock';
export { cardGridBlock } from './objects/cardGridBlock';
export { youtubeEmbedBlock } from './objects/youtubeEmbedBlock';

// Document types
export { person } from './documents/person';
export { sermon } from './documents/sermon';
export { event } from './documents/event';
export { ministry } from './documents/ministry';
export { page } from './documents/page';

// Singletons
export { siteSettings } from './singletons/siteSettings';
export { navigation } from './singletons/navigation';
export { homePage } from './singletons/homePage';

import { heroBlock } from './objects/heroBlock';
import { imageMosaicBlock } from './objects/imageMosaicBlock';
import { accordionBlock } from './objects/accordionBlock';
import { cardGridBlock } from './objects/cardGridBlock';
import { youtubeEmbedBlock } from './objects/youtubeEmbedBlock';
import { person } from './documents/person';
import { sermon } from './documents/sermon';
import { event } from './documents/event';
import { ministry } from './documents/ministry';
import { page } from './documents/page';
import { siteSettings } from './singletons/siteSettings';
import { navigation } from './singletons/navigation';
import { homePage } from './singletons/homePage';

/** All schema types to register with Sanity */
export const schemaTypes = [
  // Objects
  heroBlock,
  imageMosaicBlock,
  accordionBlock,
  cardGridBlock,
  youtubeEmbedBlock,
  // Documents
  person,
  sermon,
  event,
  ministry,
  page,
  // Singletons
  siteSettings,
  navigation,
  homePage,
];

/** Singleton type names — used by structure builder to filter from default list */
export const singletonTypes = new Set(['siteSettings', 'navigation', 'homePage']);

/** Singleton document IDs per language */
export const singletonDocIds = [
  { id: 'siteSettings-en', type: 'siteSettings', title: 'Site Settings (EN)' },
  { id: 'siteSettings-zh', type: 'siteSettings', title: 'Site Settings (ZH)' },
  { id: 'navigation-en', type: 'navigation', title: 'Navigation (EN)' },
  { id: 'navigation-zh', type: 'navigation', title: 'Navigation (ZH)' },
  { id: 'homePage-en', type: 'homePage', title: 'Home Page (EN)' },
  { id: 'homePage-zh', type: 'homePage', title: 'Home Page (ZH)' },
];

---
interface Props {
  title: string;
  body?: string;
  image?: string;
  href?: string;
}

const { title, body, image, href } = Astro.props;
const Tag = href ? 'a' : 'div';
---

<Tag class="card" {...(href ? { href } : {})}>
  {image && (
    <div class="card__image-wrap">
      <img class="card__image" src={image} alt="" loading="lazy" />
    </div>
  )}
  <div class="card__body">
    <h3 class="card__title">{title}</h3>
    {body && <p class="card__text">{body}</p>}
  </div>
</Tag>

<style>
  .card {
    display: flex;
    flex-direction: column;
    border-radius: var(--radius-md);
    border: 1px solid var(--color-stone);
    background-color: var(--color-bg);
    overflow: hidden;
    text-decoration: none;
    color: inherit;
    transition: box-shadow var(--transition), transform var(--transition);
  }

  a.card:hover {
    box-shadow: 0 4px 16px rgba(26, 26, 46, 0.1);
    transform: translateY(-2px);
  }

  a.card:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  .card__image-wrap {
    aspect-ratio: 3 / 2;
    overflow: hidden;
  }

  .card__image {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  .card__body {
    padding: var(--space-6);
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
  }

  .card__title {
    font-family: var(--font-heading);
    font-size: var(--text-lg);
    line-height: var(--leading-tight);
    color: var(--color-ink);
  }

  .card__text {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
  }
</style>

---
import BaseLayout from '../layouts/BaseLayout.astro';
import Hero from '../components/Hero.astro';
import ServiceTimes from '../components/ServiceTimes.astro';
import ImageMosaic from '../components/ImageMosaic.astro';
import Pillars from '../components/Pillars.astro';
import Card from '../components/Card.astro';
import NextSteps from '../components/NextSteps.astro';
import { getHomePage, getSermons, getEvents, urlForImage } from '../lib/sanity';

const title = 'First Ithaca Chinese Christian Church | 伊的家華人基督教會';
const description =
  'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY. Sunday gathering at 9:45am, 429 Mitchell Street.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let homePage: Awaited<ReturnType<typeof getHomePage>> = null;
let sermons: Awaited<ReturnType<typeof getSermons>> = [];
let events: Awaited<ReturnType<typeof getEvents>> = [];

try {
  [homePage, sermons, events] = await Promise.all([
    getHomePage('en'),
    getSermons('en'),
    getEvents('en'),
  ]);
} catch {
  // Sanity unreachable (placeholder project, no network, etc.) — continue with fallbacks
}

// ---------- Fallback defaults ----------
const fallbackServiceTimes = [
  { label: 'Sunday Gathering', time: '9:45 AM' },
  { label: 'Sunday School', time: '11:15 AM' },
];

const fallbackPillars = [
  {
    title: 'Rooted in Scripture',
    description:
      "We hold to the Bible as God's inspired Word and the foundation for all of life and faith.",
  },
  {
    title: 'Christ-Centered Community',
    description:
      'We gather as a Christ-centered community, welcoming students, families, and neighbors of all backgrounds.',
  },
  {
    title: 'Bridging Cultures',
    description:
      'We celebrate our Chinese heritage while building a church home that bridges cultures and generations.',
  },
];

const fallbackNextSteps = [
  {
    title: 'Plan Your Visit',
    body: 'Join us Sunday at 9:45 AM. Learn what to expect and how to find us.',
    href: '/visit',
  },
  {
    title: 'Get Connected',
    body: 'Discover small groups, ministries, and ways to grow alongside others.',
    href: '/ministries',
  },
  {
    title: 'Watch Sermons',
    body: 'Catch up on recent messages or explore a teaching series.',
    href: '/sermons',
  },
];

// ---------- Resolved data (CMS ▸ fallback) ----------
const heroImage = homePage?.heroImage
  ? urlForImage(homePage.heroImage, { width: 1600 })
  : '/images/hero-placeholder.svg';
const heroTitle = homePage?.heroTitle || 'Welcome Home';
const heroSubtitle =
  homePage?.heroSubtitle ||
  'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.';
const heroCtaText = homePage?.heroCtaText || 'Plan Your Visit';
const heroCtaHref = homePage?.heroCtaHref || '/visit';

const serviceTimes =
  homePage?.serviceTimes && homePage.serviceTimes.length > 0
    ? homePage.serviceTimes
    : fallbackServiceTimes;

const mosaicImages =
  homePage?.mosaicImages && homePage.mosaicImages.length > 0
    ? homePage.mosaicImages.map((img) => ({
        src: urlForImage(img, { width: 800 }),
        alt: img.alt || '',
      }))
    : Array.from({ length: 6 }, (_, i) => ({
        src: `/images/placeholder-${i + 1}.svg`,
        alt: `Church life ${i + 1}`,
      }));

const pillars =
  homePage?.pillars && homePage.pillars.length > 0
    ? homePage.pillars.map((p) => ({
        title: p.title,
        description: p.description || '',
      }))
    : fallbackPillars;

const nextSteps =
  homePage?.nextSteps && homePage.nextSteps.length > 0
    ? homePage.nextSteps.map((s) => ({
        title: s.title,
        body: s.body || '',
        href: s.href || '#',
        image: s.image ? urlForImage(s.image, { width: 600 }) : undefined,
      }))
    : fallbackNextSteps;

// ---------- Featured content ----------
const latestSermon = sermons[0] ?? null;
const nextEvent = events[0] ?? null;
---

<BaseLayout title={title} description={description}>
  <main>
    <Hero
      title={heroTitle}
      subtitle={heroSubtitle}
      ctaText={heroCtaText}
      ctaHref={heroCtaHref}
      backgroundImage={heroImage}
    />

    <ServiceTimes times={serviceTimes} />

    <section class="mosaic-section" aria-label="Church Life">
      <div class="mosaic-section__inner">
        <ImageMosaic images={mosaicImages} />
      </div>
    </section>

    <Pillars pillars={pillars} />

    {(latestSermon || nextEvent) && (
      <section class="featured" aria-label="Featured">
        <div class="featured__inner">
          <h2 class="featured__heading">Stay Connected</h2>
          <div class="featured__grid">
            {latestSermon && (
              <Card
                title={latestSermon.title}
                body={latestSermon.speaker ? `Speaker: ${latestSermon.speaker}` : 'Latest sermon'}
                href="/sermons"
              />
            )}
            {nextEvent && (
              <Card
                title={nextEvent.title}
                body={nextEvent.date ? `Date: ${nextEvent.date}` : 'Upcoming event'}
                href="/events"
              />
            )}
          </div>
        </div>
      </section>
    )}

    <NextSteps steps={nextSteps} />
  </main>
</BaseLayout>

<style>
  .mosaic-section {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .mosaic-section__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .featured {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-stone);
  }

  .featured__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .featured__heading {
    font-family: var(--font-heading);
    font-size: var(--text-3xl);
    color: var(--color-ink);
    text-align: center;
    margin-block-end: var(--space-12);
  }

  .featured__grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: var(--space-8);
  }

  @media (max-width: 768px) {
    .featured__grid {
      grid-template-columns: 1fr;
      gap: var(--space-6);
    }

    .featured__heading {
      font-size: var(--text-2xl);
    }
  }
</style>

---
import '../styles/global.css';
import cjkFontsHref from '../styles/cjk-fonts.css?url';
import Header from '../components/Header.astro';
import Footer from '../components/Footer.astro';
import SEO from '../components/SEO.astro';
import { VisualEditing } from '@sanity/astro/visual-editing';

interface Props {
  title: string;
  description?: string;
  lang?: string;
}

const {
  title,
  description = 'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.',
  lang = 'en',
} = Astro.props;

const isVisualEditingEnabled =
  import.meta.env.PUBLIC_SANITY_VISUAL_EDITING_ENABLED === 'true';
---

<!doctype html>
<html lang={lang}>
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <SEO title={title} description={description} lang={lang} />
    <link rel="stylesheet" href={cjkFontsHref} media="print" onload="this.media='all'" />
    <noscript><link rel="stylesheet" href={cjkFontsHref} /></noscript>
  </head>
  <body>
    <Header />
    <slot />
    <Footer />
    {isVisualEditingEnabled && <VisualEditing enabled={true} />}
  </body>
</html>

/* ==========================================================================
   FICCC Design Tokens & Global Styles
   Palette: "Gathered Warmth" (D007)
   ========================================================================== */

/* --- Font imports (self-hosted via fontsource) --- */
@import '@fontsource-variable/lora';
@import '@fontsource-variable/inter';

/* ==========================================================================
   CSS Custom Properties
   ========================================================================== */

:root {
  /* --- Colors: Gathered Warmth palette --- */
  --color-bg:          #FAF8F5;  /* off-white background       */
  --color-stone:       #E8E0D8;  /* warm stone / borders        */
  --color-terracotta:  #C4745A;  /* muted terracotta / accent   */
  --color-ink:         #1A1A2E;  /* deep ink / headings         */
  --color-body:        #2D2D2D;  /* body text                   */

  /* --- Spacing: 4px base scale --- */
  --space-1:    4px;   /*  4 */
  --space-2:    8px;   /*  8 */
  --space-3:   12px;   /* 12 */
  --space-4:   16px;   /* 16 */
  --space-6:   24px;   /* 24 */
  --space-8:   32px;   /* 32 */
  --space-12:  48px;   /* 48 */
  --space-16:  64px;   /* 64 */
  --space-24:  96px;   /* 96 */
  --space-32: 128px;   /* 128 */

  /* --- Font families --- */
  --font-heading:  'Lora Variable', 'Noto Serif SC', Georgia, serif;
  --font-body:     'Inter Variable', 'Noto Serif SC', system-ui, sans-serif;
  --font-cjk:      'Noto Serif SC', 'Lora Variable', serif;

  /* --- Type scale (EN) — modular, ~1.25 ratio --- */
  --text-xs:     0.75rem;   /* 12px */
  --text-sm:     0.875rem;  /* 14px */
  --text-base:   1rem;      /* 16px */
  --text-lg:     1.25rem;   /* 20px */
  --text-xl:     1.5rem;    /* 24px */
  --text-2xl:    2rem;      /* 32px */
  --text-3xl:    2.5rem;    /* 40px */
  --text-4xl:    3rem;      /* 48px */

  /* --- Line heights --- */
  --leading-tight:   1.25;
  --leading-normal:  1.5;
  --leading-relaxed: 1.65;
  --leading-cjk:     1.75;

  /* --- Type scale (ZH) — slightly larger base for readability --- */
  --text-zh-base:  1.125rem;  /* 18px */
  --text-zh-lg:    1.375rem;  /* 22px */
  --text-zh-xl:    1.625rem;  /* 26px */
  --text-zh-2xl:   2.125rem;  /* 34px */
  --text-zh-3xl:   2.625rem;  /* 42px */

  /* --- Layout --- */
  --max-width:  72rem;

  /* --- Misc --- */
  --radius-sm:  4px;
  --radius-md:  8px;
  --radius-lg: 16px;
  --transition: 200ms ease;
  --color-focus: var(--color-terracotta);
  --color-bg-dark: #1A1A2E;       /* deep ink — used for footer bg */
}

/* ==========================================================================
   Minimal Reset
   ========================================================================== */

*,
*::before,
*::after {

import { defineType, defineField } from 'sanity';

export const cardGridBlock = defineType({
  name: 'cardGridBlock',
  title: 'Card Grid Block',
  type: 'object',
  fields: [
    defineField({
      name: 'cards',
      title: 'Cards',
      type: 'array',
      of: [
        {
          type: 'object',
          name: 'card',
          title: 'Card',
          fields: [
            defineField({
              name: 'title',
              title: 'Title',
              type: 'string',
              validation: (rule) => rule.required(),
            }),
            defineField({
              name: 'description',
              title: 'Description',
              type: 'string',
            }),
            defineField({
              name: 'image',
              title: 'Image',
              type: 'image',
              options: { hotspot: true },
            }),
            defineField({
              name: 'link',
              title: 'Link',
              type: 'string',
            }),
          ],
          preview: {
            select: { title: 'title' },
          },
        },
      ],
    }),
  ],
  preview: {
    select: { cards: 'cards' },
    prepare: ({ cards }) => ({
      title: `Card Grid (${cards?.length ?? 0} cards)`,
    }),
  },
});
